# check for nested fields in xml schema
def has_nested_field(schema, field_path):
    # Check if a nested field (like 'ReportResponse.ReportResults') exists in the schema    
    fields = field_path.split(".")
    current = schema
    for f in fields:
        field = next((x for x in current.fields if x.name == f), None)
        if field is None:
            return False
        if hasattr(field.dataType, "fields"):
            current = field.dataType
        else:
            return True
    return True

# flatten nested struct fields and return (full_path, alias_name)
def flatten_struct(schema, prefix="Row"):
    fields = []
    for field in schema.fields:
        full_path = f"{prefix}.{field.name}"
        if isinstance(field.dataType, StructType):
            fields += flatten_struct(field.dataType, full_path)
        else:
            fields.append((full_path, field.name))  # (full path, final field name)
    return fields

